    },
    
    //sort the first column in ascending order by default
    sortList: [[0,1]]
    
  })
  
  .on('apply.daterangepicker', function(){
    $table.trigger('search');
  })
  
  .tablesorterPager({
    // target the pager markup - see the HTML block below
    container: $(".ts-pager"),
    // target the pager page select dropdown - choose a page
    cssGoto  : ".pagenum",
    // remove rows from the table to speed up the sort of large tables.
    // setting this to false, only hides the non-visible rows; needed if you plan to add/remove rows with the pager enabled.
    removeRows: false,
    // output string - default is '{page}/{totalPages}';
    output: '{startRow} - {endRow} / {filteredRows} ({totalRows})',
    //initial number of rows per page
    size: '10'
  })
  
  $('.datepicker').daterangepicker();;
  
  $('.reset').click(function(){
    //reset page and size on pager widget
    $('#revenuetable').trigger('pageAndSize', [1, 10]);
    //reset back to sortng by first column, ascending
    $('#revenuetable').trigger( 'sorton', [ [[0,1]] ] );
  });
  
});
```

I have included the minified script from your example in another file, without it I get another error so i know it is being read.
Any ideas or thoughts would be greatly appreciated. Thanks!

Steven

